import { runIngestion } from "./ingest/index.js";
import { generateNewsletter } from "./generate/index.js";
import { sendNewsletterEmail } from "./email/send.js";
import { log } from "./logger.js";
import { writeFileSync, readFileSync } from "fs";
const command = process.argv[2];
async function main() {
    switch (command) {
        case "ingest": {
            await runIngestion();
            break;
        }
        case "generate": {
            const date = process.argv[3];
            if (!date) {
                log.error("Usage: tsx src/cli.ts generate <YYYY-MM-DD>");
                process.exit(1);
            }
            // Optional: path to previous newsletter file for dedup
            const prevNewsletterPath = process.argv[4];
            let previousNewsletter;
            if (prevNewsletterPath) {
                const { readFileSync } = await import("fs");
                previousNewsletter = readFileSync(prevNewsletterPath, "utf-8");
            }
            const newsletter = await generateNewsletter(date, previousNewsletter);
            // Write to file and stdout
            const outputPath = `newsletter-${date}.md`;
            writeFileSync(outputPath, newsletter, "utf-8");
            log.info(`Newsletter written to: ${outputPath}`);
            log.info("--- NEWSLETTER OUTPUT ---");
            console.log(newsletter);
            break;
        }
        case "email": {
            const date = process.argv[3];
            const recipient = process.argv[4];
            if (!date || !recipient) {
                log.error("Usage: tsx src/cli.ts email <YYYY-MM-DD> <recipient-email> [newsletter-file-path]");
                log.error("If newsletter-file-path is not provided, will look for newsletter-YYYY-MM-DD.md");
                process.exit(1);
            }
            // Try to read newsletter file
            let newsletterPath = process.argv[5];
            if (!newsletterPath) {
                newsletterPath = `newsletter-${date}.md`;
            }
            let newsletterContent;
            try {
                newsletterContent = readFileSync(newsletterPath, "utf-8");
            }
            catch (err) {
                log.error(`Could not read newsletter file: ${newsletterPath}`);
                log.error("Hint: Run 'npm run generate' first to create the newsletter");
                process.exit(1);
            }
            // Parse subject line from newsletter (first line, removing # prefix)
            const lines = newsletterContent.split("\n");
            const subjectLine = lines[0].replace(/^#\s+/, "").trim();
            if (!subjectLine) {
                log.error("Could not parse subject line from newsletter (expected # Subject as first line)");
                process.exit(1);
            }
            log.info(`Sending newsletter for ${date} to ${recipient}`);
            log.info(`Subject: ${subjectLine}`);
            try {
                const result = await sendNewsletterEmail({
                    to: recipient,
                    subjectLine,
                    markdownBody: newsletterContent,
                    htmlBody: "", // Will be generated by sendNewsletterEmail
                });
                log.info("Newsletter sent successfully", { emailId: result.id });
                console.log(`✅ Email sent! ID: ${result.id}`);
            }
            catch (err) {
                log.error("Failed to send newsletter", { error: err instanceof Error ? err.message : String(err) });
                process.exit(1);
            }
            break;
        }
        case "send": {
            const date = process.argv[3];
            if (!date) {
                log.error("Usage: tsx src/cli.ts send <YYYY-MM-DD> [newsletter-file-path]");
                log.error("This command sends to all recipients in NEWSLETTER_RECIPIENTS env var");
                process.exit(1);
            }
            // Get recipients from environment
            const recipientsEnv = process.env.NEWSLETTER_RECIPIENTS;
            if (!recipientsEnv) {
                log.error("Missing NEWSLETTER_RECIPIENTS environment variable");
                log.error("Set it to comma-separated email addresses");
                process.exit(1);
            }
            const recipients = recipientsEnv.split(",").map(email => email.trim()).filter(Boolean);
            if (recipients.length === 0) {
                log.error("No recipients found in NEWSLETTER_RECIPIENTS");
                process.exit(1);
            }
            // Try to read newsletter file
            let newsletterPath = process.argv[4];
            if (!newsletterPath) {
                newsletterPath = `newsletter-${date}.md`;
            }
            let newsletterContent;
            try {
                newsletterContent = readFileSync(newsletterPath, "utf-8");
            }
            catch (err) {
                log.error(`Could not read newsletter file: ${newsletterPath}`);
                log.error("Hint: Run 'npm run generate' first to create the newsletter");
                process.exit(1);
            }
            // Parse subject line from newsletter
            const lines = newsletterContent.split("\n");
            const subjectLine = lines[0].replace(/^#\s+/, "").trim();
            if (!subjectLine) {
                log.error("Could not parse subject line from newsletter");
                process.exit(1);
            }
            log.info(`Sending newsletter for ${date} to ${recipients.length} recipient(s)`);
            log.info(`Recipients: ${recipients.join(", ")}`);
            log.info(`Subject: ${subjectLine}`);
            try {
                const result = await sendNewsletterEmail({
                    to: recipients,
                    subjectLine,
                    markdownBody: newsletterContent,
                    htmlBody: "",
                });
                log.info("Newsletter sent successfully", { emailId: result.id, recipientCount: recipients.length });
                console.log(`✅ Email sent to ${recipients.length} recipient(s)! ID: ${result.id}`);
            }
            catch (err) {
                log.error("Failed to send newsletter", { error: err instanceof Error ? err.message : String(err) });
                process.exit(1);
            }
            break;
        }
        default: {
            console.log(`AI Newsletter CLI\n\nUsage:\n  tsx src/cli.ts ingest                          Fetch & process all RSS feeds\n  tsx src/cli.ts generate <YYYY-MM-DD> [prev]    Generate newsletter for a date\n  tsx src/cli.ts email <YYYY-MM-DD> <recipient>  Send generated newsletter via email\n\nArguments:\n  <YYYY-MM-DD>   Date to generate newsletter for (must have ingested content)\n  [prev]         Optional path to previous newsletter markdown (for dedup)\n  <recipient>    Email address to send newsletter to\n\nEnvironment:\n  Copy .env.example to .env and fill in your API keys.\n  Required for email: RESEND_API_KEY, NEWSLETTER_RECIPIENTS (comma-separated)`);
            break;
        }
    }
}
main().catch((err) => {
    log.error("Fatal error", { error: err instanceof Error ? err.message : String(err) });
    process.exit(1);
});
